func GetDashboard(ctx context.Context) (*DashboardResponse, error) {
	uid, _ := auth.UserID()
	data := auth.Data().(*auth_pkg.Data)

	return &DashboardResponse{
		Message: fmt.Sprintf("Hello %s, you are an %s", uid, data.Role),
	}, nil
}

